item.description:
Vue筆記5.for迴圈 若我們希望某個元素重複出現，例如卡片或商品外框
但是內容要求不同，例如商品名稱，我們可採用v-for
&lt;!DOCTYPE html&gt; &lt;html lang=&#34;zh-hant-TW&#34;&gt; &lt;head&gt; &lt;meta charset=&#34;UTF-8&#34;&gt; &lt;title&gt;簡化版Vue學習&lt;/title&gt; &lt;/head&gt; &lt;body&gt; &lt;!--要插入的目標位置--&gt; &lt;div id=&#34;tag01&#34;&gt; &lt;!--要執行迴圈的標籤--&gt; &lt;!--item可以隨意命名，此處只是個代號--&gt; &lt;div v-for=&#34;item in items&#34;&gt; {{item.text}} &lt;/div&gt; &lt;/div&gt; &lt;/body&gt; &lt;!--引入Vue--&gt; &lt;script src=&#34;https://cdn.jsdelivr.net/npm/vue&#34;&gt;&lt;/script&gt; &lt;script&gt; //建立陣列元素  var element = [{ text: &#34;仁愛&#34; }, { text: &#34;喜樂&#34; }, { text: &#34;和平&#34; }, { text: &#34;忍耐&#34; }] //將陣列元素放入data  var object01 = new Vue({ el: &#39;#tag01&#39;, data: { items: element } }) &lt;/script&gt; &lt;/html&gt;
